CREATE TABLE IF NOT EXISTS bibliography_entries (
 bibliography_id TEXT PRIMARY KEY,
 source_id TEXT NOT NULL REFERENCES sources(source_id),
 category TEXT NOT NULL,
 raw_entry_fa TEXT NOT NULL,
 normalization_status TEXT NOT NULL DEFAULT 'raw',
 notes TEXT
);
CREATE TABLE IF NOT EXISTS artifacts (
 artifact_id TEXT PRIMARY KEY,
 source_id TEXT NOT NULL REFERENCES sources(source_id),
 printed_page TEXT,
 artifact_type TEXT NOT NULL,
 title TEXT NOT NULL,
 caption_fa TEXT,
 description TEXT,
 transcription_status TEXT NOT NULL,
 confidence TEXT NOT NULL,
 file_reference TEXT,
 notes TEXT
);
CREATE TABLE IF NOT EXISTS artifact_persons (
 artifact_id TEXT NOT NULL REFERENCES artifacts(artifact_id) ON DELETE CASCADE,
 person_id TEXT NOT NULL REFERENCES persons(person_id) ON DELETE CASCADE,
 role TEXT NOT NULL,
 notes TEXT,
 PRIMARY KEY (artifact_id, person_id, role)
);
