INSERT OR IGNORE INTO claims VALUES('C0104','source','S0001','author_concludes','The initial hypothesis limiting Gharagozloo presence in Iran to the Mongol period was rejected; the author places their arrival in the late fourth or early fifth AH century.','confirmed','active','This records the author’s conclusion, not independent proof of the underlying chronology.');
