INSERT OR IGNORE INTO claims VALUES('C0105','source','S0001','author_concludes','The Gharagozloos were Turkic-speaking and belonged under the Bigdili grouping, described as one of the twenty-four major Oghuz tribes.','confirmed','active','Authorial conclusion.');
INSERT OR IGNORE INTO claim_citations VALUES('C0105','X0056','supports');
