INSERT OR IGNORE INTO claims VALUES('C0106','source','S0001','author_concludes','After the Mongol invasion, the Gharagozloos moved west toward Syria, joined other Turkic groups, and became associated with the Shamlu confederation.','confirmed','active','Authorial conclusion.');
INSERT OR IGNORE INTO claim_citations VALUES('C0106','X0057','supports');
