INSERT OR IGNORE INTO claims VALUES('C0107','source','S0001','author_concludes','Timur moved them eastward; they later settled again on the Iranian plateau and entered the Safavid Qizilbash confederation.','confirmed','active','Authorial conclusion.');
INSERT OR IGNORE INTO claim_citations VALUES('C0107','X0058','supports');
INSERT OR IGNORE INTO citations(citation_id,source_id,page_printed,page_file,locator_text,quoted_text,notes) VALUES('X0059','S0001','187-188',NULL,'Conclusion',NULL,'Conclusion pages.');
INSERT OR IGNORE INTO claims VALUES('C0108','source','S0001','author_concludes','Under Shah Abbas and in the late Safavid period, the Gharagozloos regained prominence and their presence around Hamadan became clear.','confirmed','active','Authorial conclusion.');
